import React from "react";
import "./SignIn.css";
import googleIcon from "../assets/google-icon.png";
import appleIcon from "../assets/apple-icon.png";
import studentsImg from "../assets/students.png"; // <-- bonequinhos

interface SignInProps {
  onGoogle: () => void;
  onApple: () => void;
}

const SignIn: React.FC<SignInProps> = ({ onGoogle, onApple }) => {
  return (
    <div className="signin-container">
      <div className="signin-card">
        {/* Logo VibeU */}
        <h1 className="signin-logo">
          VibeU <span>✨</span>
        </h1>

        {/* Texto de boas-vindas */}
        <h2 className="signin-subtitle">Bem-vindo 👋</h2>
        <p className="signin-text">Conecte-se com colegas do mundo todo</p>

        {/* Botões de login */}
        <button className="signin-button google" onClick={onGoogle}>
          <img src={googleIcon} alt="Google" />
          Entrar com Google
        </button>

        <button className="signin-button apple" onClick={onApple}>
          <img src={appleIcon} alt="Apple" />
          Entrar com Apple
        </button>

        {/* Imagem rodapé */}
        <div className="signin-footer">
          <img src={studentsImg} alt="Estudantes" />
        </div>
      </div>
    </div>
  );
};

export default SignIn;
