import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import "./OnboardingWizard.css";

interface OnboardingWizardProps {
  onDone: () => void;
}

const OnboardingWizard: React.FC<OnboardingWizardProps> = ({ onDone }) => {
  const [step, setStep] = useState(1);

  const nextStep = () => setStep((prev) => prev + 1);
  const prevStep = () => setStep((prev) => prev - 1);

  return (
    <div className="onboarding-container">
      <motion.div
        className="onboarding-card"
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 0.4 }}
      >
        <h1 className="wizard-title">✨ VibeU - Configuração Inicial</h1>

        <AnimatePresence mode="wait">
          {step === 1 && (
            <motion.div
              key="step1"
              className="wizard-step"
              initial={{ opacity: 0, x: -50 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 50 }}
              transition={{ duration: 0.5 }}
            >
              <p>👋 Bem-vindo! Vamos começar sua jornada no VibeU.</p>
              <button onClick={nextStep} className="btn-next">
                Próximo →
              </button>
            </motion.div>
          )}

          {step === 2 && (
            <motion.div
              key="step2"
              className="wizard-step"
              initial={{ opacity: 0, x: -50 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 50 }}
              transition={{ duration: 0.5 }}
            >
              <p>🎓 Escolha sua universidade para personalizar sua experiência.</p>
              <input type="text" placeholder="Digite sua universidade" />
              <div className="wizard-nav">
                <button onClick={prevStep} className="btn-back">
                  ← Voltar
                </button>
                <button onClick={nextStep} className="btn-next">
                  Próximo →
                </button>
              </div>
            </motion.div>
          )}

          {step === 3 && (
            <motion.div
              key="step3"
              className="wizard-step"
              initial={{ opacity: 0, x: -50 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 50 }}
              transition={{ duration: 0.5 }}
            >
              <p>🚀 Tudo pronto! Clique em concluir para começar.</p>
              <div className="wizard-nav">
                <button onClick={prevStep} className="btn-back">
                  ← Voltar
                </button>
                <button onClick={onDone} className="btn-finish">
                  Concluir 🎉
                </button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.div>
    </div>
  );
};

export default OnboardingWizard;
