import React, { useEffect, useMemo, useState } from "react";
import { auth } from "../firebase";
import {
  getFeedForUser,
  getFeedByUniversity,
  getUniversities,
  publishPost,
  PostWithAuthor,
  subscribeNewPosts,
} from "../api";
import PostItem from "../components/PostItem";

export default function Feed() {
  const [posts, setPosts] = useState<PostWithAuthor[]>([]);
  const [text, setText] = useState("");
  const [unis, setUnis] = useState<string[]>([]);
  const [selectedUni, setSelectedUni] = useState<string>("Todos");
  const user = auth.currentUser!;
  const canPublish = useMemo(() => text.trim().length > 0, [text]);

  useEffect(() => { getUniversities().then(setUnis).catch(() => setUnis([])); }, []);

  useEffect(() => {
    let off = () => {};
    (async () => {
      const list =
        selectedUni === "Todos"
          ? await getFeedForUser(user.uid, 50)
          : await getFeedByUniversity(user.uid, selectedUni, 50);
      setPosts(list);
      off = subscribeNewPosts((p) =>
        setPosts((cur) =>
          selectedUni === "Todos" ? [{ ...p, likedByMe: false }, ...cur] : cur
        )
      );
    })();
    return () => off();
  }, [user.uid, selectedUni]);

  async function handlePublish() {
    const content = text.trim();
    if (!content) return;

    const optimistic: PostWithAuthor = {
      id: `tmp-${Date.now()}`,
      author_id: user.uid,
      content,
      likes_count: 0,
      comments_count: 0,
      created_at: new Date().toISOString(),
      author: {
        id: user.uid,
        email: user.email,
        display_name: user.displayName ?? user.email,
        university: null, dob: null, photo_url: null,
      },
      likedByMe: false,
    };
    setPosts((cur) => [optimistic, ...cur]);
    setText("");

    try {
      const saved = await publishPost(user.uid, content);
      setPosts((cur) => {
        const i = cur.findIndex((x) => x.id === optimistic.id);
        if (i >= 0) {
          const clone = [...cur];
          clone[i] = { ...saved, author: optimistic.author, likedByMe: false };
          return clone;
        }
        return cur;
      });
    } catch (e: any) {
      alert(e.message ?? "Falha ao publicar");
      setPosts((cur) => cur.filter((x) => x.id !== optimistic.id));
      setText(content);
    }
  }

  return (
    <div>
      <div className="toolbar">
        <select
          value={selectedUni}
          onChange={(e) => setSelectedUni(e.target.value)}
          title="Filtrar por universidade"
        >
          <option>Todos</option>
          {unis.map((u) => (
            <option key={u} value={u}>{u}</option>
          ))}
        </select>
        <select><option>Classificar</option></select>
      </div>

      <div className="card composer">
        <textarea
          placeholder="O que você está pensando?"
          value={text}
          onChange={(e) => setText(e.target.value)}
          maxLength={280}
        />
        <div className="composer-actions">
          <button className="btn" onClick={handlePublish} disabled={!canPublish}>
            Publicar
          </button>
        </div>
      </div>

      <div className="feed">
        {posts.map((p) => <PostItem key={p.id} post={p} />)}
      </div>
    </div>
  );
}
