import React, { useState, useEffect } from "react";
import SignIn from "./pages/SignIn";
import OnboardingWizard from "./components/OnboardingWizard";
import Feed from "./pages/Feed";
import "./App.css";

const App: React.FC = () => {
  const [user, setUser] = useState<any>(null);
  const [needsOnboarding, setNeedsOnboarding] = useState(false);
  const [currentView, setCurrentView] = useState("signin"); // controla a tela atual

  useEffect(() => {
    // Simulação de login
    const loggedUser = localStorage.getItem("user");
    const onboardingDone = localStorage.getItem("onboardingComplete");

    if (loggedUser) {
      setUser(loggedUser);
      setCurrentView(onboardingDone === "true" ? "feed" : "onboarding");
    } else {
      setCurrentView("signin");
    }
  }, []);

  // 🔹 Handlers
  const handleGoogleLogin = () => {
    localStorage.setItem("user", "googleUser");
    setUser("googleUser");
    setCurrentView("onboarding");
  };

  const handleAppleLogin = () => {
    localStorage.setItem("user", "appleUser");
    setUser("appleUser");
    setCurrentView("onboarding");
  };

  const handleOnboardingDone = () => {
    localStorage.setItem("onboardingComplete", "true");
    setNeedsOnboarding(false);
    setCurrentView("feed");
  };

  return (
    <div className="app-wrapper">
      <div className="fade-wrapper">
        {currentView === "signin" && (
          <div className="fade-in">
            <SignIn onGoogle={handleGoogleLogin} onApple={handleAppleLogin} />
          </div>
        )}

        {currentView === "onboarding" && (
          <div className="fade-in">
            <OnboardingWizard onDone={handleOnboardingDone} />
          </div>
        )}

        {currentView === "feed" && (
          <div className="fade-in">
            <Feed />
          </div>
        )}
      </div>
    </div>
  );
};

export default App;
