import React, { useEffect, useState } from "react";
import { auth } from "../firebase";
import {
  PostWithAuthor,
  toggleLike,
  getCommentsWithAuthors,
  addComment,
  deleteComment,
  CommentWithAuthor,
} from "../api";
import { supabase } from "../supabase";
import { timeAgo } from "../time";

type Props = { post: PostWithAuthor };

export default function PostItem({ post }: Props) {
  const user = auth.currentUser!;
  const [p, setP] = useState<PostWithAuthor>(post);
  const [open, setOpen] = useState(false);
  const [comments, setComments] = useState<CommentWithAuthor[]>([]);
  const [loadingComments, setLoadingComments] = useState(false);
  const [newComment, setNewComment] = useState("");

  // mantém o card sincronizado com o post recebido
  useEffect(() => setP(post), [post]);

  // Realtime: atualiza contadores (likes/comments) quando o trigger mexe em posts
  useEffect(() => {
    const ch = supabase
      .channel(`post-${post.id}`)
      .on("postgres_changes",
        { event: "UPDATE", schema: "public", table: "posts", filter: `id=eq.${post.id}` },
        (payload: any) => {
          const row = payload.new as { likes_count: number; comments_count: number };
          setP(cur => ({ ...cur, likes_count: row.likes_count, comments_count: row.comments_count }));
        }
      )
      .subscribe();
    return () => { supabase.removeChannel(ch); };
  }, [post.id]);

  // Realtime: insere/deleta comentários desse post
  useEffect(() => {
    const ch = supabase
      .channel(`comments-${post.id}`)
      .on("postgres_changes",
        { event: "INSERT", schema: "public", table: "comments", filter: `post_id=eq.${post.id}` },
        async () => {
          // só atualiza lista se o painel estiver aberto
          if (open) {
            const list = await getCommentsWithAuthors(post.id);
            setComments(list);
          }
        }
      )
      .on("postgres_changes",
        { event: "DELETE", schema: "public", table: "comments", filter: `post_id=eq.${post.id}` },
        async () => {
          if (open) {
            const list = await getCommentsWithAuthors(post.id);
            setComments(list);
          }
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(ch); };
  }, [post.id, open]);

  async function onToggleLike() {
    try {
      const liked = await toggleLike(p.id, user.uid);
      setP((cur) => ({
        ...cur,
        likedByMe: liked,
        likes_count: cur.likes_count + (liked ? 1 : -1),
      }));
    } catch (e: any) {
      alert(e.message ?? "Erro ao curtir/descurtir");
    }
  }

  async function toggleComments() {
    if (open) {
      setOpen(false);
      return;
    }
    setOpen(true);
    if (comments.length === 0) {
      try {
        setLoadingComments(true);
        const list = await getCommentsWithAuthors(p.id);
        setComments(list);
      } finally {
        setLoadingComments(false);
      }
    }
  }

  async function onSendComment(e: React.FormEvent) {
    e.preventDefault();
    const content = newComment.trim();
    if (!content) return;
    try {
      const created = await addComment(p.id, user.uid, content);

      // atualiza local de imediato
      setComments((cur) => [
        ...cur,
        {
          ...created,
          author: {
            id: user.uid,
            email: user.email,
            display_name: user.displayName ?? user.email,
            university: p.author?.university ?? null,
            dob: null,
            photo_url: p.author?.photo_url ?? null,
          },
        },
      ]);
      setP((cur) => ({ ...cur, comments_count: cur.comments_count + 1 }));
      setNewComment("");
      // o trigger + realtime cuidam de todo mundo
    } catch (e: any) {
      alert(e.message ?? "Erro ao comentar");
    }
  }

  async function onDeleteComment(c: CommentWithAuthor) {
    if (c.user_id !== user.uid) return;
    const ok = window.confirm("Apagar este comentário?");
    if (!ok) return;
    try {
      await deleteComment(c.id, user.uid);
      setComments((cur) => cur.filter((x) => x.id !== c.id));
      setP((cur) => ({
        ...cur,
        comments_count: Math.max(cur.comments_count - 1, 0),
      }));
      // o trigger + realtime cuidam do resto
    } catch (e: any) {
      alert(e.message ?? "Erro ao apagar comentário");
    }
  }

  return (
    <article className="post card">
      <div className="post-head">
        <img
          className="avatar"
          src={p.author?.photo_url || `https://i.pravatar.cc/64?u=${p.author_id}`}
          alt=""
        />
        <div className="who">
          <strong>{p.author?.display_name || "Estudante"}</strong>{" "}
          <span className="muted">
            {p.author?.university ? `— ${p.author.university}` : ""}
          </span>
          <div className="muted">{timeAgo(p.created_at)}</div>
        </div>
        <button className="more">•••</button>
      </div>

      <p className="post-text">{p.content}</p>

      <div className="post-actions muted">
        <span onClick={onToggleLike} style={{ cursor: "pointer" }}>
          {p.likedByMe ? "♥" : "♡"} {p.likes_count} curtidas
        </span>
        <span onClick={toggleComments} style={{ cursor: "pointer" }}>
          💬 {p.comments_count} comentários
        </span>
      </div>

      {open && (
        <div className="comments">
          {loadingComments && (
            <div className="muted">Carregando comentários…</div>
          )}
          {comments.map((c) => (
            <div className="comment" key={c.id}>
              <img
                className="avatar"
                src={c.author?.photo_url || `https://i.pravatar.cc/48?u=${c.user_id}`}
                alt=""
              />
              <div className="bubble">
                <div className="name">
                  <strong>{c.author?.display_name || "Estudante"}</strong>{" "}
                  <span className="muted">{timeAgo(c.created_at)}</span>
                </div>
                <div>{c.content}</div>
                {c.user_id === user.uid && (
                  <div className="muted" style={{ textAlign: "right" }}>
                    <button className="btn ghost" onClick={() => onDeleteComment(c)}>
                      Apagar
                    </button>
                  </div>
                )}
              </div>
            </div>
          ))}

          <form className="comment-input" onSubmit={onSendComment}>
            <input
              placeholder="Escreva um comentário…"
              value={newComment}
              onChange={(e) => setNewComment(e.target.value)}
              maxLength={280}
            />
            <button className="btn" type="submit" disabled={!newComment.trim()}>
              Enviar
            </button>
          </form>
        </div>
      )}
    </article>
  );
}
